import sys

class Solution:
    def removeStones(self, stones: list[list[int]]) -> int:
        parent = {}
        rank = {}
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]
        def union(x, y):
            rx, ry = find(x), find(y)
            if rx == ry:
                return
            if rank[rx] < rank[ry]:
                parent[rx] = ry
            elif rank[rx] > rank[ry]:
                parent[ry] = rx
            else:
                parent[ry] = rx
                rank[rx] += 1
        # map rows and columns to separate ids to avoid collision
        offset = 10001  # since x,y <= 10000
        for x, y in stones:
            row_id = x
            col_id = y + offset
            for node in (row_id, col_id):
                if node not in parent:
                    parent[node] = node
                    rank[node] = 0
            union(row_id, col_id)
        # count unique roots among all nodes that appear
        roots = set()
        for node in parent:
            roots.add(find(node))
        # number of connected components equals number of roots
        # each component can keep one stone, so removable = total stones - components
        return len(stones) - len(roots)

if __name__ == '__main__':
