#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class DSU {
public:
    unordered_map<int,int> parent;
    unordered_map<int,int> rankv;
    int find(int x){
        if(parent[x]!=x) parent[x]=find(parent[x]);
        return parent[x];
    }
    void unite(int x,int y){
        int rx=find(x), ry=find(y);
        if(rx==ry) return;
        if(rankv[rx]<rankv[ry]) parent[rx]=ry;
        else if(rankv[rx]>rankv[ry]) parent[ry]=rx;
        else{ parent[ry]=rx; rankv[rx]++; }
    }
    void add(int x){
        if(parent.find(x)==parent.end()){
            parent[x]=x; rankv[x]=0;
        }
    }
};

class Solution {
public:
    int removeStones(vector<vector<int>>& stones) {
        DSU dsu;
        const int OFFSET = 10001; // y offset to separate rows and columns
        for(const auto& s: stones){
            int row = s[0];
            int col = s[1] + OFFSET;
            dsu.add(row);
            dsu.add(col);
            dsu.unite(row, col);
        }
        unordered_set<int> roots;
        for(const auto& kv: dsu.parent){
            roots.insert(dsu.find(kv.first));
        }
        return (int)stones.size() - (int)roots.size();
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<vector<int>> stones(n, vector<int>(2));
    for(int i=0;i<n;++i){
        cin>>stones[i][0]>>stones[i][1];
    }
    Solution sol;
    int ans = sol.removeStones(stones);
    cout<<ans<<"\n";
    return 0;
}
